const tel = String($('When Executed by Another Workflow').item.json.telefono || '').replace(/[^0-9]/g, '');
const clientes = $input.all();
let cliente_id = '';
for (const c of clientes) {
  const p = c.json.properties || {};
  const stored = String(p['Telefono']?.phone_number || '').replace(/[^0-9]/g, '');
  if (stored && tel && (stored === tel || stored.endsWith(tel) || tel.endsWith(stored))) {
    cliente_id = c.json.id;
    break;
  }
}
return [{ json: { encontrado: !!cliente_id, cliente_id } }];

const clienteId = $('Match cliente').item.json.cliente_id;
const hoy = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Santiago' });

const reservas = $input.all().filter(i => {
  const p = i.json && i.json.properties;
  if (!p || !i.json.id) return false;
  const clientes = (p['👤 Clientes Genten']?.relation || []).map(c => c.id);
  if (!clientes.includes(clienteId)) return false;
  const estado = p['Estado']?.select?.name || '';
  const f = p['Fecha']?.date?.start ? String(p['Fecha'].date.start).slice(0, 10) : '';
  return estado === 'Reservado' && f && f >= hoy;
}).sort((a, b) => {
  const fa = String(a.json.properties['Fecha'].date.start).slice(0, 10);
  const fb = String(b.json.properties['Fecha'].date.start).slice(0, 10);
  return fa < fb ? -1 : fa > fb ? 1 : 0;
});

if (reservas.length === 0) {
  return [{ json: { encontrado: false, mensaje: 'No tienes reservas activas (Reservado) de hoy en adelante.' } }];
}

const primera = reservas[0];
const p = primera.json.properties;
const nombre   = p['Titulo']?.title?.[0]?.plain_text || 'N/A';
const servicio = p['Servicio']?.select?.name || 'N/A';
const vehiculo = p['Vehiculo']?.select?.name || 'N/A';
const fecha    = p['Fecha']?.date?.start || 'N/A';
const hora     = p['Hora recepcion ']?.rich_text?.[0]?.plain_text || p['Hora recepcion']?.rich_text?.[0]?.plain_text || 'N/A';

const resumen = `${servicio} para ${vehiculo} el ${fecha} a las ${hora}`;

return [{ json: {
  encontrado: true,
  page_id: primera.json.id,
  nombre_cliente: nombre,
  servicio, vehiculo, fecha, hora,
  total_reservas: reservas.length,
  resumen,
  mensaje: `Encontré tu reserva: ${resumen}.`
} }];

const tel = $('When Executed by Another Workflow').item.json.telefono;
return [{ json: {
  encontrado: false,
  mensaje: 'No encontré tu número en nuestra base de datos. ¿Tienes alguna reserva agendada con nosotros?'
} }];
